private StringBuffer appendQuotedString(String pattern, ParsePosition pos, StringBuffer appendTo, boolean escapingOn) {
    int start = pos.getIndex();
    char[] c = pattern.toCharArray();
    if (escapingOn && c[start] == QUOTE) {
        // Increment index after processing an escaped quote
        pos.setIndex(start + 1);
        return appendTo == null ? new StringBuffer().append(QUOTE) : appendTo.append(QUOTE);
    }
    int lastHold = start;
    boolean quoteFound = false;
    for (int i = pos.getIndex(); i < pattern.length(); i++) {
        if (escapingOn && pattern.startsWith(ESCAPED_QUOTE, i)) {
            if (appendTo != null) {
                appendTo.append(c, lastHold, i - lastHold).append(QUOTE);
            }
            i += ESCAPED_QUOTE.length() - 1;
            pos.setIndex(i + 1);
            lastHold = pos.getIndex();
            continue;
        }
        if (c[i] == QUOTE) {
            quoteFound = true;
            pos.setIndex(i + 1);
            break;
        }
    }
    if (!quoteFound) {
        throw new IllegalArgumentException("Unterminated quoted string at position " + start);
    }
    if (appendTo != null) {
        appendTo.append(c, lastHold, pos.getIndex() - 1 - lastHold);
    }
    return appendTo;
}
